"use client";

import { useState, useEffect, useCallback, useRef, useMemo } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import {
  Loader2,
  ChevronLeft,
  ChevronRight,
  RefreshCw,
  CheckSquare,
  Square,
  Trash2,
  X,
} from "lucide-react";
import { apiGet, apiPost, API_URL } from "@/lib/api";
import { PostDetailModal } from "@/components/post-detail-modal";
import { useProfile } from "@/contexts/profile-context";
import { toast } from "sonner";
import { friendlyPlatformName } from "@/lib/platforms";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";

/* ---------- Types ---------- */

export interface PostizPost {
  id: string;
  content: string;
  publish_date: string;
  state: "QUEUE" | "PUBLISHED" | "ERROR" | "DRAFT";
  release_url?: string;
  platform: string;
  platform_name: string;
  platform_picture?: string;
  source?: string;
  group?: string | null;
}

/** Short label for the platform shown inside calendar cells. */
export function shortPlatformLabel(platform: string | undefined): string {
  const p = (platform || "").toLowerCase();
  const map: Record<string, string> = {
    tiktok: "TT",
    instagram: "IG",
    youtube: "YT",
    facebook: "FB",
    twitter: "X",
    x: "X",
    linkedin: "LI",
    pinterest: "PI",
    threads: "TH",
  };
  return map[p] || (p ? p.slice(0, 2).toUpperCase() : "??");
}

export interface ScheduleItem {
  id: string;
  clip_id: string;
  clip_name: string;
  thumbnail_path?: string;
  final_video_path?: string;
  scheduled_date: string;
  scheduled_at: string;
  status: string;
  postiz_post_id?: string;
  error_message?: string;
  source?: string;
  platform_type?: string;
}

export interface CalendarData {
  postiz_posts: PostizPost[];
  schedule_items: ScheduleItem[];
  days: Record<string, { postiz_count: number; scheduled_count: number; published_count: number }>;
}

/** A not-yet-confirmed clip from the Smart Schedule preview, drawn as a ghost chip. */
export interface PreviewEntry {
  date: string; // YYYY-MM-DD
  clip_id: string;
  clip_name: string;
  collection_name: string;
  thumbnail_path?: string;
  final_video_path?: string;
  platform_type?: string;
  variant_index?: number;
}

interface PostizMonthlyCalendarProps {
  /** Optional title override (default: "Publishing Calendar") */
  title?: string;
  /** Called after calendar data is fetched, so parent can access it */
  onDataLoaded?: (data: CalendarData) => void;
  /** Unconfirmed preview clips to overlay as ghost chips (Smart Schedule). */
  previewEntries?: PreviewEntry[];
}

/* ---------- Constants ---------- */

const WEEKDAY_LABELS = ["Mon", "Tue", "Wed", "Thu", "Fri", "Sat", "Sun"];

const MONTH_NAMES = [
  "January", "February", "March", "April", "May", "June",
  "July", "August", "September", "October", "November", "December",
];

/* ---------- Helpers ---------- */

function stateColor(state: string): string {
  switch (state) {
    case "PUBLISHED": return "bg-green-500/20 text-green-300 border-green-500/30";
    case "QUEUE": return "bg-amber-500/20 text-amber-300 border-amber-500/30";
    case "ERROR": return "bg-red-500/20 text-red-300 border-red-500/30";
    case "DRAFT": return "bg-muted text-muted-foreground border-border";
    default: return "bg-muted text-muted-foreground border-border";
  }
}

function stripHtml(html: string): string {
  return html.replace(/<[^>]*>/g, "").replace(/&amp;/g, "&").replace(/&lt;/g, "<").replace(/&gt;/g, ">").trim();
}

function getMonthCalendarDays(year: number, month: number): { date: string; isCurrentMonth: boolean }[] {
  const days: { date: string; isCurrentMonth: boolean }[] = [];

  const firstDay = new Date(year, month, 1);
  let startDow = firstDay.getDay();
  startDow = startDow === 0 ? 6 : startDow - 1;

  const lastDay = new Date(year, month + 1, 0);
  const daysInMonth = lastDay.getDate();

  for (let i = startDow - 1; i >= 0; i--) {
    const d = new Date(year, month, -i);
    days.push({ date: d.toISOString().split("T")[0], isCurrentMonth: false });
  }

  for (let d = 1; d <= daysInMonth; d++) {
    const dt = new Date(year, month, d);
    days.push({ date: dt.toISOString().split("T")[0], isCurrentMonth: true });
  }

  const remaining = 7 - (days.length % 7);
  if (remaining < 7) {
    for (let i = 1; i <= remaining; i++) {
      const d = new Date(year, month + 1, i);
      days.push({ date: d.toISOString().split("T")[0], isCurrentMonth: false });
    }
  }

  return days;
}

/* ---------- Component ---------- */

/** Legend entries mapping calendar chip colours to their meaning. */
const LEGEND: { label: string; state: string }[] = [
  { label: "Scheduled", state: "QUEUE" },
  { label: "Published", state: "PUBLISHED" },
  { label: "Failed", state: "ERROR" },
];

export function PostizMonthlyCalendar({ title = "Publishing Calendar", onDataLoaded, previewEntries }: PostizMonthlyCalendarProps) {
  // Store callback in ref to avoid re-fetch loops
  const onDataLoadedRef = useRef(onDataLoaded);
  onDataLoadedRef.current = onDataLoaded;

  const { currentProfile } = useProfile();

  const [viewYear, setViewYear] = useState(() => new Date().getFullYear());
  const [viewMonth, setViewMonth] = useState(() => new Date().getMonth());
  const [calendarData, setCalendarData] = useState<CalendarData | null>(null);
  const [loadingCalendar, setLoadingCalendar] = useState(false);
  const [selectedPost, setSelectedPost] = useState<PostizPost | null>(null);
  const [selectionMode, setSelectionMode] = useState(false);
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
  const [bulkDeleting, setBulkDeleting] = useState(false);
  const [showDeleteConfirm, setShowDeleteConfirm] = useState(false);
  const [previewVideo, setPreviewVideo] = useState<PreviewEntry | null>(null);

  const monthDays = useMemo(() => getMonthCalendarDays(viewYear, viewMonth), [viewYear, viewMonth]);

  const previewByDate = useMemo(() => {
    const map: Record<string, PreviewEntry[]> = {};
    for (const e of previewEntries || []) {
      const date = e.date.split("T")[0];
      (map[date] ||= []).push(e);
    }
    return map;
  }, [previewEntries]);

  // Jump the calendar to the first preview day so ghosts are visible immediately.
  const firstPreviewDate = previewEntries?.[0]?.date;
  useEffect(() => {
    if (!firstPreviewDate) return;
    const d = new Date(firstPreviewDate + "T00:00:00");
    setViewYear(d.getFullYear());
    setViewMonth(d.getMonth());
  }, [firstPreviewDate]);

  const dateRange = useMemo(() => {
    if (monthDays.length === 0) return { start: "", end: "" };
    return {
      start: monthDays[0].date,
      end: monthDays[monthDays.length - 1].date,
    };
  }, [monthDays]);

  const todayStr = useMemo(() => new Date().toISOString().split("T")[0], []);

  const postsByDate = useMemo(() => {
    if (!calendarData) return {};
    const map: Record<string, PostizPost[]> = {};
    for (const post of calendarData.postiz_posts) {
      const date = post.publish_date.split("T")[0];
      if (!map[date]) map[date] = [];
      map[date].push(post);
    }
    // Sort posts within each day chronologically by publish_date
    for (const date of Object.keys(map)) {
      map[date].sort((a, b) => new Date(a.publish_date).getTime() - new Date(b.publish_date).getTime());
    }
    return map;
  }, [calendarData]);

  const scheduleItemsByDate = useMemo(() => {
    if (!calendarData) return {};
    const map: Record<string, ScheduleItem[]> = {};
    for (const item of calendarData.schedule_items) {
      // Buffer publications are rendered as posts; keep the linked item only for modal preview.
      if (item.source === "buffer") continue;
      const date = item.scheduled_date.split("T")[0];
      if (!map[date]) map[date] = [];
      map[date].push(item);
    }
    // Sort schedule items within each day chronologically
    for (const date of Object.keys(map)) {
      map[date].sort((a, b) => new Date(a.scheduled_at).getTime() - new Date(b.scheduled_at).getTime());
    }
    return map;
  }, [calendarData]);

  const postToScheduleItem = useMemo(() => {
    if (!calendarData) return new Map<string, ScheduleItem>();
    const map = new Map<string, ScheduleItem>();
    for (const item of calendarData.schedule_items) {
      if (item.postiz_post_id) {
        map.set(item.postiz_post_id, item);
      }
    }
    return map;
  }, [calendarData]);

  const selectedPostSiblings = useMemo((): PostizPost[] => {
    if (!selectedPost || !calendarData) return [];
    if (selectedPost.group) {
      return calendarData.postiz_posts.filter(p => p.group === selectedPost.group);
    }
    // Fallback for Postiz instances that don't return group: match by content + date
    return calendarData.postiz_posts.filter(
      p => p.publish_date === selectedPost.publish_date && p.content === selectedPost.content
    );
  }, [selectedPost, calendarData]);

  const handlePostDeleted = useCallback((postId: string) => {
    setCalendarData(prev => {
      if (!prev) return prev;
      return {
        ...prev,
        postiz_posts: prev.postiz_posts.filter(p => p.id !== postId),
        schedule_items: prev.schedule_items.filter(item => item.postiz_post_id !== postId),
      };
    });
  }, []);

  /* ---------- Selection ---------- */

  const toggleSelect = useCallback((postId: string) => {
    setSelectedIds(prev => {
      const next = new Set(prev);
      if (next.has(postId)) next.delete(postId);
      else next.add(postId);
      return next;
    });
  }, []);

  const selectAllForDate = useCallback((dateStr: string) => {
    const posts = postsByDate[dateStr] || [];
    setSelectedIds(prev => {
      const next = new Set(prev);
      const allSelected = posts.every(p => next.has(p.id));
      for (const p of posts) {
        if (allSelected) next.delete(p.id);
        else next.add(p.id);
      }
      return next;
    });
  }, [postsByDate]);

  const selectAllVisible = useCallback(() => {
    if (!calendarData) return;
    setSelectedIds(prev => {
      const allIds = calendarData.postiz_posts.map(p => p.id);
      const allSelected = allIds.length > 0 && allIds.every(id => prev.has(id));
      return allSelected ? new Set() : new Set(allIds);
    });
  }, [calendarData]);

  const exitSelectionMode = useCallback(() => {
    setSelectionMode(false);
    setSelectedIds(new Set());
    setShowDeleteConfirm(false);
  }, []);

  const handleBulkDelete = useCallback(async () => {
    if (selectedIds.size === 0) return;
    setBulkDeleting(true);
    try {
      const res = await apiPost("/postiz/posts/bulk-delete", {
        post_ids: Array.from(selectedIds),
      });
      const data = await res.json();
      if (data.total_deleted > 0) {
        const deletedSet = new Set(data.deleted as string[]);
        setCalendarData(prev => {
          if (!prev) return prev;
          return {
            ...prev,
            postiz_posts: prev.postiz_posts.filter(p => !deletedSet.has(p.id)),
          };
        });
        toast.success(`${data.total_deleted} post(s) deleted`);
      }
      if (data.total_failed > 0) {
        toast.error(`${data.total_failed} post(s) failed to delete`);
      }
      exitSelectionMode();
    } catch (err) {
      console.error("Bulk delete failed:", err);
      toast.error("Bulk delete failed");
    } finally {
      setBulkDeleting(false);
      setShowDeleteConfirm(false);
    }
  }, [selectedIds, exitSelectionMode]);

  /* ---------- Fetch ---------- */

  const fetchCalendar = useCallback(async () => {
    if (!dateRange.start) return;
    // Clear stale data so the previous profile's posts never linger after a switch.
    setCalendarData(null);
    setLoadingCalendar(true);
    try {
      const res = await apiGet(
        `/schedule/calendar?start_date=${dateRange.start}&end_date=${dateRange.end}`
      );
      const data: CalendarData = await res.json();
      setCalendarData(data);
      onDataLoadedRef.current?.(data);
    } catch (err) {
      console.error("Failed to load calendar:", err);
    } finally {
      setLoadingCalendar(false);
    }
  }, [dateRange, currentProfile?.id]);

  useEffect(() => { fetchCalendar(); }, [fetchCalendar]);

  // Drop any in-flight selection when the active profile changes — selected IDs
  // belong to the previous profile's posts and must not bleed into the new one.
  useEffect(() => { exitSelectionMode(); }, [currentProfile?.id, exitSelectionMode]);

  /* ---------- Navigation ---------- */

  const goToPrevMonth = () => {
    if (viewMonth === 0) {
      setViewYear(y => y - 1);
      setViewMonth(11);
    } else {
      setViewMonth(m => m - 1);
    }
  };

  const goToNextMonth = () => {
    if (viewMonth === 11) {
      setViewYear(y => y + 1);
      setViewMonth(0);
    } else {
      setViewMonth(m => m + 1);
    }
  };

  const goToToday = () => {
    const now = new Date();
    setViewYear(now.getFullYear());
    setViewMonth(now.getMonth());
  };

  /* ---------- Weeks ---------- */

  const weeks = useMemo(() => {
    const result: typeof monthDays[] = [];
    for (let i = 0; i < monthDays.length; i += 7) {
      result.push(monthDays.slice(i, i + 7));
    }
    return result;
  }, [monthDays]);

  /* ---------- Render ---------- */

  return (
    <Card>
      <CardHeader className="pb-3">
        <div className="flex items-center justify-between">
          <CardTitle className="text-base">{title}</CardTitle>
          <div className="flex items-center gap-1.5">
            <Button variant="outline" size="icon" className="size-8" onClick={goToPrevMonth}>
              <ChevronLeft className="size-4" />
            </Button>
            <Button
              variant="ghost"
              size="sm"
              className="text-sm font-semibold px-3 min-w-[160px] justify-center"
              onClick={goToToday}
            >
              {MONTH_NAMES[viewMonth]} {viewYear}
            </Button>
            <Button variant="outline" size="icon" className="size-8" onClick={goToNextMonth}>
              <ChevronRight className="size-4" />
            </Button>
            <Button variant="outline" size="sm" onClick={fetchCalendar} disabled={loadingCalendar} className="ml-2">
              <RefreshCw className={`size-3.5 mr-1.5 ${loadingCalendar ? "animate-spin" : ""}`} />
              Sync
            </Button>
            {!selectionMode ? (
              <Button
                variant="outline"
                size="sm"
                onClick={() => setSelectionMode(true)}
                disabled={!calendarData || calendarData.postiz_posts.length === 0}
                className="ml-1"
              >
                <CheckSquare className="size-3.5 mr-1.5" />
                Select
              </Button>
            ) : (
              <Button variant="ghost" size="sm" onClick={exitSelectionMode} className="ml-1">
                <X className="size-3.5 mr-1.5" />
                Cancel
              </Button>
            )}
          </div>
        </div>

        {/* Selection toolbar */}
        {selectionMode && (
          <div className="flex items-center gap-2 mt-2 pt-2 border-t">
            <Button variant="outline" size="sm" onClick={selectAllVisible}>
              {calendarData && selectedIds.size === calendarData.postiz_posts.length && calendarData.postiz_posts.length > 0
                ? "Deselect All"
                : "Select All"}
            </Button>
            <span className="text-sm text-muted-foreground">
              {selectedIds.size} selected
            </span>
            <div className="flex-1" />
            {showDeleteConfirm ? (
              <div className="flex items-center gap-2">
                <span className="text-sm text-destructive font-medium">
                  Delete {selectedIds.size} post(s)?
                </span>
                <Button
                  variant="destructive"
                  size="sm"
                  onClick={handleBulkDelete}
                  disabled={bulkDeleting}
                >
                  {bulkDeleting ? <Loader2 className="size-3.5 mr-1.5 animate-spin" /> : <Trash2 className="size-3.5 mr-1.5" />}
                  Confirm
                </Button>
                <Button variant="ghost" size="sm" onClick={() => setShowDeleteConfirm(false)} disabled={bulkDeleting}>
                  No
                </Button>
              </div>
            ) : (
              <Button
                variant="destructive"
                size="sm"
                disabled={selectedIds.size === 0}
                onClick={() => setShowDeleteConfirm(true)}
              >
                <Trash2 className="size-3.5 mr-1.5" />
                Delete Selected ({selectedIds.size})
              </Button>
            )}
          </div>
        )}

        {/* Legend — explains what the coloured chips in each day cell mean */}
        <div className="flex flex-wrap items-center gap-3 mt-2 pt-2 border-t">
          {LEGEND.map(({ label, state }) => (
            <span key={state} className="flex items-center gap-1.5 text-xs text-muted-foreground">
              <span className={`inline-block size-2.5 rounded-sm border ${stateColor(state)}`} />
              {label}
            </span>
          ))}
        </div>
      </CardHeader>
      <CardContent className="p-0">
        {loadingCalendar && !calendarData ? (
          <div className="flex items-center justify-center py-16">
            <Loader2 className="size-6 animate-spin text-muted-foreground" />
          </div>
        ) : (
          <div className="border-t">
            {/* Weekday header */}
            <div className="grid grid-cols-7">
              {WEEKDAY_LABELS.map((day, i) => (
                <div
                  key={day}
                  className={`px-2 py-2 text-center text-xs font-semibold uppercase tracking-wider text-muted-foreground ${
                    i < 6 ? "border-r" : ""
                  } border-b bg-muted/30`}
                >
                  {day}
                </div>
              ))}
            </div>

            {/* Week rows */}
            {weeks.map((week, weekIdx) => (
              <div key={weekIdx} className="grid grid-cols-7">
                {week.map(({ date: dateStr, isCurrentMonth }, dayIdx) => {
                  const isToday = dateStr === todayStr;
                  const dayNum = new Date(dateStr + "T00:00:00").getDate();
                  const posts = postsByDate[dateStr] || [];
                  const items = scheduleItemsByDate[dateStr] || [];
                  const ghosts = previewByDate[dateStr] || [];
                  const totalItems = posts.length + items.length + ghosts.length;

                  return (
                    <div
                      key={dateStr}
                      className={`min-h-[90px] flex flex-col ${
                        dayIdx < 6 ? "border-r" : ""
                      } ${weekIdx < weeks.length - 1 ? "border-b" : ""} ${
                        !isCurrentMonth ? "bg-muted/10" : ""
                      } ${isToday ? "bg-primary/5" : ""}`}
                    >
                      {/* Day number header */}
                      <div className="flex items-center justify-between px-1.5 py-1">
                        <div className="flex items-center gap-1">
                          {selectionMode && posts.length > 0 && (
                            <button
                              className="text-muted-foreground hover:text-foreground transition-colors"
                              onClick={(e) => { e.stopPropagation(); selectAllForDate(dateStr); }}
                              title={`Select all posts for this day`}
                            >
                              {posts.every(p => selectedIds.has(p.id))
                                ? <CheckSquare className="size-3" />
                                : <Square className="size-3" />}
                            </button>
                          )}
                          <span
                            className={`text-xs leading-none ${
                              isToday
                                ? "bg-primary text-primary-foreground rounded-full size-6 flex items-center justify-center font-bold"
                                : isCurrentMonth
                                ? "text-foreground font-medium"
                                : "text-muted-foreground/50"
                            }`}
                          >
                            {dayNum}
                          </span>
                        </div>
                        {totalItems > 0 && (
                          <Badge variant="secondary" className="text-[9px] px-1 py-0 h-4">
                            {totalItems}
                          </Badge>
                        )}
                      </div>

                      {/* Posts & items in this day */}
                      <div className="flex-1 px-1 pb-1 space-y-0.5 overflow-y-auto">
                        {posts.map((post) => {
                          const timeStr = post.publish_date
                            ? new Date(post.publish_date).toLocaleTimeString("en-US", {
                                hour: "2-digit",
                                minute: "2-digit",
                                hour12: false,
                              })
                            : "";
                          const isSelected = selectedIds.has(post.id);
                          return (
                            <div
                              key={post.id}
                              className={`rounded px-1 py-0.5 text-[10px] leading-tight border cursor-pointer hover:opacity-80 transition-opacity ${stateColor(post.state)} ${
                                selectionMode && isSelected ? "ring-1 ring-primary" : ""
                              }`}
                              title={`[${post.state}] ${post.platform_name} · ${friendlyPlatformName(post.platform)}\n${timeStr}\n${stripHtml(post.content || "(no content)")}`}
                              onClick={() => selectionMode ? toggleSelect(post.id) : setSelectedPost(post)}
                            >
                              <div className="flex items-center gap-1">
                                {selectionMode ? (
                                  isSelected
                                    ? <CheckSquare className="size-3 shrink-0 text-primary" />
                                    : <Square className="size-3 shrink-0" />
                                ) : post.platform_picture ? (
                                  <img src={post.platform_picture} alt="" className="size-3 rounded-full shrink-0" />
                                ) : (
                                  <span className="text-[8px] font-bold px-1 rounded bg-background/60 border shrink-0" title={post.platform_name}>
                                    {shortPlatformLabel(post.platform)}
                                  </span>
                                )}
                                <span className="truncate font-medium">
                                  {timeStr && <span className="opacity-70 mr-0.5">{timeStr}</span>}
                                  {post.content ? stripHtml(post.content).slice(0, 20) : post.platform_name}
                                </span>
                              </div>
                            </div>
                          );
                        })}

                        {items.map((item) => {
                          const timeStr = item.scheduled_at
                            ? new Date(item.scheduled_at).toLocaleTimeString("en-US", {
                                hour: "2-digit",
                                minute: "2-digit",
                                hour12: false,
                              })
                            : "";
                          const itemState =
                            item.status === "published" ? "PUBLISHED"
                              : item.status === "scheduled" ? "QUEUE"
                              : item.status === "failed" ? "ERROR"
                              : "DRAFT";
                          return (
                            <div
                              key={item.id}
                              className={`rounded px-1 py-0.5 text-[10px] leading-tight border ${
                                item.postiz_post_id ? "cursor-pointer hover:opacity-80 transition-opacity" : "cursor-default"
                              } ${stateColor(itemState)}`}
                              title={`[${item.status}] ${item.clip_name}\n${timeStr}`}
                              onClick={() => {
                                if (item.postiz_post_id) {
                                  const linkedPost = calendarData?.postiz_posts.find(p => p.id === item.postiz_post_id);
                                  if (linkedPost) setSelectedPost(linkedPost);
                                }
                              }}
                            >
                              <div className="flex items-center gap-1">
                                {item.thumbnail_path ? (
                                  <img src={item.thumbnail_path} alt="" className="size-3 rounded shrink-0" />
                                ) : null}
                                <span className="truncate font-medium">
                                  {timeStr && <span className="opacity-70 mr-0.5">{timeStr}</span>}
                                  {item.clip_name}
                                </span>
                              </div>
                            </div>
                          );
                        })}

                        {ghosts.map((g, gi) => {
                          const hasVideo = !!g.final_video_path;
                          return (
                            <div
                              key={`ghost-${g.clip_id}-${g.platform_type ?? gi}`}
                              className={`rounded px-1 py-0.5 text-[10px] leading-tight border border-dashed border-primary/60 bg-primary/5 text-primary ${
                                hasVideo ? "cursor-pointer hover:opacity-80 transition-opacity" : "cursor-default"
                              }`}
                              title={`Preview · ${g.clip_name}${g.platform_type ? ` · ${friendlyPlatformName(g.platform_type)}` : ""}`}
                              onClick={() => hasVideo && setPreviewVideo(g)}
                            >
                              <div className="flex items-center gap-1">
                                {g.thumbnail_path ? (
                                  <img
                                    src={`${API_URL}/library/files/${encodeURIComponent(g.thumbnail_path)}?v=${g.clip_id}`}
                                    alt=""
                                    className="size-3 rounded shrink-0"
                                  />
                                ) : null}
                                <span className="truncate font-medium">
                                  {g.platform_type && (
                                    <span className="opacity-70 mr-0.5">{shortPlatformLabel(g.platform_type)}</span>
                                  )}
                                  {g.clip_name}
                                </span>
                              </div>
                            </div>
                          );
                        })}
                      </div>
                    </div>
                  );
                })}
              </div>
            ))}
          </div>
        )}
      </CardContent>

      <PostDetailModal
        post={selectedPost}
        scheduleItem={selectedPost ? postToScheduleItem.get(selectedPost.id) : undefined}
        siblings={selectedPostSiblings}
        onClose={() => setSelectedPost(null)}
        onDeleted={handlePostDeleted}
      />

      {/* Preview clip playback (ghost chips, before confirming a schedule) */}
      <Dialog open={!!previewVideo} onOpenChange={(open) => { if (!open) setPreviewVideo(null); }}>
        <DialogContent className="max-w-md p-0 overflow-hidden">
          <DialogHeader className="px-4 pt-4 pb-2">
            <DialogTitle className="text-sm font-medium">{previewVideo?.clip_name}</DialogTitle>
          </DialogHeader>
          {previewVideo?.final_video_path ? (
            <div className="aspect-[9/16] bg-black">
              <video
                key={previewVideo.clip_id}
                src={`${API_URL}/library/files/${encodeURIComponent(previewVideo.final_video_path)}?v=${previewVideo.clip_id}`}
                controls
                autoPlay
                className="w-full h-full object-contain"
              />
            </div>
          ) : (
            <div className="aspect-[9/16] bg-muted flex items-center justify-center text-muted-foreground text-sm">
              Video not available
            </div>
          )}
        </DialogContent>
      </Dialog>
    </Card>
  );
}
